def sanitize_path(base_dir, user_path):
    from pathlib import Path

    # Validate user_path
    user = Path(user_path)
    if user.is_absolute():
        return None
    base = Path(base_dir).resolve(strict=False)
    combined = base / user
    try:
        resolved = combined.resolve(strict=False)
    except Exception:
        return None
    try:
        # relative_to will be ValueError if not subpath
        resolved.relative_to(base)
        return str(resolved)
    except ValueError:
        return None
